        code: '# Install TypeScript LSP plugin\n/plugin install typescript-lsp@claude-plugins-official\n# Requires: typescript-language-server in $PATH\n\n# Install Python LSP plugin\n/plugin install pyright-lsp@claude-plugins-official\n# Requires: pyright-langserver in $PATH\n\n# Other available LSP plugins:\n# clangd-lsp (C/C++), gopls-lsp (Go), rust-analyzer-lsp (Rust)\n# kotlin-lsp, java (jdtls-lsp), swift-lsp, php-lsp, lua-lsp, csharp-lsp\n\n# What Claude gains:\n# - Automatic diagnostics after every file edit (type errors, missing imports)\n# - Code navigation: jump to definitions, find references, get type info\n# - Claude sees and fixes type errors in the same turn it introduces them\n\n# If you see "Executable not found in $PATH" in the /plugin Errors tab:\n# Install the required binary (e.g., npm install -g typescript-language-server)',
